DO $$ DECLARE v_lesson_id uuid; BEGIN
  SELECT id INTO v_lesson_id FROM lessons WHERE module_id = 'a4ce8c6c-ea88-45fb-b590-05fb329347c3' AND order_index = 6;
  IF v_lesson_id IS NULL THEN
    INSERT INTO lessons (course_id, module_id, institution_id, title, order_index, content_type, content_url, is_required)
    VALUES ('6b4906f1-803b-40bb-8582-d591220e5d09', 'a4ce8c6c-ea88-45fb-b590-05fb329347c3', '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'Lesson 5: Types of Advocacy', 6, 'blocks', '', true)
    RETURNING id INTO v_lesson_id;
  END IF;
  DELETE FROM lesson_blocks WHERE lesson_id = v_lesson_id;
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', 'Lesson 5: Types of Advocacy', '{"html":"<p>In this lesson, we will address:</p><ol><li><p>Individual - Driven Advocacy</p></li><li><p>Patient Organization - Driven Advocacy</p></li></ol>\n<img src=\"fit_content_assets/writing_higx0s.jpg\" alt=\"\" />\n<p></p><p></p>\n<p></p>\n<p></p>\n<p></p>","media":[{"type":"image","url":"fit_content_assets/writing_higx0s.jpg"}],"mode":"scrolling"}'::jsonb, 0, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', 'Individual-Driven Advocacy', '{"html":"<p>In patient advocacy, individual-driven efforts are led by those affected by one or more diseases. This approach is often referred to as self-advocacy and the individuals engaging in the advocacy act are referred to as self-advocates. </p><p></p><p>An individual(s) affected by a disease is addressed as a person/people with lived disease experience.</p><p>Lived-disease experience is different for different people. Some have lived-disease experience because they are living with the disease, some because they are caregivers and others because they advocate to support people living with the disease(s).</p>\n<img src=\"fit_content_assets/Advocacy-timetotakeaction_h48ljv.jpg\" alt=\"\" />\n<p>The individual(s) affected by a disease may or may not be affiliated with a patient organization.</p>","media":[{"type":"image","url":"fit_content_assets/Advocacy-timetotakeaction_h48ljv.jpg"}],"mode":"scrolling"}'::jsonb, 1, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', '', '{"html":"","mode":"fallback","original_type":"multiple-choice-game"}'::jsonb, 2, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', '', '{"html":"","mode":"fallback","original_type":"multiple-choice-game"}'::jsonb, 3, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', 'Patient Organization-Driven Advocacy', '{"html":"<p>Patient organizations are organizations established solely to advance a cause relating to one or more diseases. This type of organizations have non-profit and/or charitable status.</p><p>With the principle of \"Nothing About Us Without Us\", these types of organizations typically include people with lived-disease experience in their governance.</p>\n<img src=\"fit_content_assets/Action_Day-2_ar32wx.png\" alt=\"\" />\n<p> Patient organizations may advocate on behalf of their members with governments, hospital administrators and staff, workplaces, and schools.  </p>","media":[{"type":"image","url":"fit_content_assets/Action_Day-2_ar32wx.png"}],"mode":"scrolling"}'::jsonb, 4, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', '', '{"html":"","mode":"fallback","original_type":"multiple-choice-game"}'::jsonb, 5, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'rich_text', '', '{"html":"","mode":"fallback","original_type":"multiple-choice-game"}'::jsonb, 6, true, 1, '{}'::jsonb);
  INSERT INTO lesson_blocks (lesson_id, institution_id, block_type, title, data, order_index, is_visible, version, settings)
  VALUES (v_lesson_id, '725f40e5-a317-4b8f-80b8-1df6cf3bbe2a', 'cta', '', '{"action":"complete_lesson","text":"Nice work. You''ve completed this lesson.","button_label":"Exit Lesson"}'::jsonb, 7, true, 1, '{}'::jsonb); END $$;